div.select:
-- Selecciona un proyecto --
{% for proyecto in proyectos %}
{{ proyecto }}
{% endfor %}

body.script:
        let archivoActual = null;
        let codigoModificado = null;
        let lenguajeActual = null;

        // Cargar archivos del proyecto seleccionado
        function cargarArchivos() {
            const project = document.getElementById('project').value;
            if (!project) return;

            fetch('/api/listar-archivos', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({directorio: project})
            })
            .then(response => response.json())
            .then(data => {
                const fileList = document.getElementById('fileList');
                if (data.error) {
                    fileList.innerHTML = `
${data.error}`;
                    return;
                }

                if (data.archivos.length === 0) {
                    fileList.innerHTML = '
No hay archivos compatibles en este proyecto';
                    return;
                }

                // Agrupar por lenguaje
                const porLenguaje = {};
                data.archivos.forEach(archivo => {
                    if (!porLenguaje[archivo.lenguaje]) {
                        porLenguaje[archivo.lenguaje] = [];
                    }
                    porLenguaje[archivo.lenguaje].push(archivo);
                });

                let html = '';
                for (const [lenguaje, archivos] of Object.entries(porLenguaje)) {
                    html += `
${lenguaje}`;
                    archivos.forEach(archivo => {
                        const tamanoKB = (archivo.tamano / 1024).toFixed(2);
                        html += `

                            📄 ${archivo.nombre} (${tamanoKB} KB)
                        `;
                    });
                    html += '';
                }

                fileList.innerHTML = html;
            })
            .catch(error => {
                document.getElementById('fileList').innerHTML = `
Error: ${error}`;
            });
        }

        // Cargar contenido de un archivo
        function cargarArchivo(ruta) {
            fetch('/api/leer-archivo', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({ruta: ruta})
            })
            .then(response => response.json())
            .then(data => {
                if (data.error) {
                    alert(data.error);
                    return;
                }

                archivoActual = ruta;
                lenguajeActual = data.lenguaje;
                document.getElementById('currentFile').innerHTML = `📄 ${data.nombre}`;
                document.getElementById('codeArea').value = data.contenido;
                document.getElementById('codeArea').readOnly = false;
                document.getElementById('saveBtn').disabled = false;
                document.getElementById('downloadBtn').disabled = false;
                document.getElementById('processBtn').disabled = false;
                document.getElementById('fileInfo').innerHTML = `Lenguaje: ${data.lenguaje} | Tamaño: ${data.contenido.length} caracteres`;

                // Ocultar vista previa si estaba abierta
                document.getElementById('previewSection').style.display = 'none';
            });
        }

        // Procesar con IA
        function procesarConIA() {
            if (!archivoActual) {
                alert('Selecciona un archivo primero');
                return;
            }

            const instrucciones = document.getElementById('instructions').value;
            if (!instrucciones) {
                alert('Escribe las instrucciones para la IA');
                return;
            }

            const accion = document.getElementById('aiAction').value;
            const processBtn = document.getElementById('processBtn');
            processBtn.disabled = true;
            processBtn.textContent = '⏳ Procesando...';

            fetch('/api/modificar-archivo', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    ruta: archivoActual,
                    instrucciones: instrucciones,
                    accion: accion
                })
            })
            .then(response => response.json())
            .then(data => {
                if (data.error) {
                    alert(data.error);
                    return;
                }

                // Mostrar vista previa
                document.getElementById('originalCode').textContent = data.codigo_original;
                document.getElementById('modifiedCode').textContent = data.codigo_modificado;
                document.getElementById('previewSection').style.display = 'block';

                codigoModificado = data.codigo_modificado;
            })
            .catch(error => {
                alert('Error: ' + error);
            })
            .finally(() => {
                processBtn.disabled = false;
                processBtn.textContent = '🚀 Procesar con IA';
            });
        }

        // Aplicar cambios (actualizar editor)
        function aplicarCambios() {
            document.getElementById('codeArea').value = codigoModificado;
            document.getElementById('previewSection').style.display = 'none';
            codigoModificado = null;
        }

        // Cancelar cambios
        function cancelarCambios() {
            document.getElementById('previewSection').style.display = 'none';
            codigoModificado = null;
        }

        // Guardar cambios en el archivo
        function guardarCambios() {
            if (!archivoActual) return;

            const contenido = document.getElementById('codeArea').value;

            fetch('/api/guardar-archivo', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    ruta: archivoActual,
                    contenido: contenido
                })
            })
            .then(response => response.json())
            .then(data => {
                if (data.error) {
                    alert('Error al guardar: ' + data.error);
                } else {
                    alert('✅ Archivo guardado correctamente');
                    // Actualizar info
                    document.getElementById('fileInfo').innerHTML =
                        `Lenguaje: ${lenguajeActual} | Tamaño: ${contenido.length} caracteres (guardado)`;
                }
            });
        }

        // Descargar archivo
        function descargarArchivo() {
            if (!archivoActual) return;

            const contenido = document.getElementById('codeArea').value;
            const nombre = archivoActual.split('/').pop() || archivoActual.split('\\').pop();

            const blob = new Blob([contenido], {type: 'text/plain'});
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = nombre;
            a.click();
            window.URL.revokeObjectURL(url);
        }

        // Modal nuevo archivo
        function mostrarModalNuevo() {
            document.getElementById('newFileModal').style.display = 'block';
        }

        function cerrarModalNuevo() {
            document.getElementById('newFileModal').style.display = 'none';
            document.getElementById('newFileContent').value = '';
        }

        function generarContenidoInicial() {
            const nombre = document.getElementById('newFileName').value;
            const lenguaje = document.getElementById('newFileLanguage').value;

            if (!nombre) {
                alert('Escribe un nombre para el archivo');
                return;
            }

            const descripcion = `Crea un archivo ${lenguaje} llamado ${nombre} con una estructura básica y funcional.`;

            fetch('/api/modificar-archivo', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    ruta: archivoActual || 'temp',
                    instrucciones: descripcion,
                    accion: 'generar'
                })
            })
            .then(response => response.json())
            .then(data => {
                if (data.error) {
                    alert(data.error);
                } else {
                    document.getElementById('newFileContent').value = data.codigo_modificado;
                }
            });
        }

        function crearArchivo() {
            const project = document.getElementById('project').value;
            const nombre = document.getElementById('newFileName').value;
            const contenido = document.getElementById('newFileContent').value;

            if (!project || !nombre) {
                alert('Selecciona un proyecto y escribe un nombre');
                return;
            }

            fetch('/api/crear-archivo', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    directorio: project,
                    nombre: nombre,
                    contenido: contenido
                })
            })
            .then(response => response.json())
            .then(data => {
                if (data.error) {
                    alert('Error: ' + data.error);
                } else {
                    alert('✅ Archivo creado correctamente');
                    cerrarModalNuevo();
                    cargarArchivos(); // Recargar lista
                }
            });
        }

        // Cerrar modal si se hace clic fuera
        window.onclick = function(event) {
            const modal = document.getElementById('newFileModal');
            if (event.target == modal) {
                modal.style.display = 'none';
            }
        }
